class CSVFormatTest(unittest.TestCase):

    def testWithSystemRecordSeparator_test1_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withSystemRecordSeparator()
        self.assertEqual(
            os.linesep,
            format_with_record_separator.getRecordSeparator(),
            "Record separator does not match the system line separator",
        )

    def testWithSystemRecordSeparator_test0_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withSystemRecordSeparator()

    def testWithRecordSeparatorLF_test2_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.LF
        )
        self.assertEqual(
            Constants.LF,
            format_with_record_separator.getRecordSeparator(),
            "Record separator does not match expected value",
        )

    def testWithRecordSeparatorLF_test1_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.LF
        )
        str(Constants.LF)

    def testWithRecordSeparatorLF_test0_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.LF
        )

    def testWithRecordSeparatorCRLF_test1_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator1(
            Constants.CRLF
        )
        self.assertEqual(
            Constants.CRLF,
            format_with_record_separator.getRecordSeparator(),
            "Record separator does not match expected CRLF",
        )

    def testWithRecordSeparatorCRLF_test0_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator1(
            Constants.CRLF
        )

    def testWithRecordSeparatorCR_test2_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.CR
        )
        self.assertEqual(
            Constants.CR,
            format_with_record_separator.getRecordSeparator(),
            "Record separator does not match expected value",
        )

    def testWithRecordSeparatorCR_test1_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.CR
        )
        str(Constants.CR)

    def testWithRecordSeparatorCR_test0_decomposed(self) -> None:
        format_with_record_separator = CSVFormat.DEFAULT.withRecordSeparator0(
            Constants.CR
        )

    def testWithQuotePolicy_test1_decomposed(self) -> None:
        format_with_quote_policy = CSVFormat.DEFAULT.withQuoteMode(QuoteMode.ALL)
        self.assertEqual(QuoteMode.ALL, format_with_quote_policy.getQuoteMode())

    def testWithQuotePolicy_test0_decomposed(self) -> None:
        format_with_quote_policy = CSVFormat.DEFAULT.withQuoteMode(QuoteMode.ALL)

    def testWithQuoteLFThrowsException_test0_decomposed(self) -> None:
        with self.assertRaises(ValueError):
            CSVFormat.DEFAULT.withQuote0(Constants.LF)

    def testWithQuoteChar_test2_decomposed(self) -> None:
        format_with_quote_char = CSVFormat.DEFAULT.withQuote0('"')
        self.assertEqual(
            '"',
            format_with_quote_char.getQuoteCharacter(),
            "Quote character does not match expected value",
        )

    def testWithQuoteChar_test1_decomposed(self) -> None:
        format_with_quote_char = CSVFormat.DEFAULT.withQuote0('"')
        assert '"' == '"'

    def testWithQuoteChar_test0_decomposed(self) -> None:
        format_with_quote_char = CSVFormat.DEFAULT.withQuote0('"')

    def testWithNullString_test1_decomposed(self) -> None:
        format_with_null_string = CSVFormat.DEFAULT.withNullString("null")
        self.assertEqual(
            "null",
            format_with_null_string.getNullString(),
            "Null string does not match expected value",
        )

    def testWithNullString_test0_decomposed(self) -> None:
        format_with_null_string = CSVFormat.DEFAULT.withNullString("null")

    def testWithIgnoreSurround_test3_decomposed(self) -> None:
        format1 = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces1(False)
        self.assertFalse(
            format1.getIgnoreSurroundingSpaces(),
            "Expected getIgnoreSurroundingSpaces to return False when set to False",
        )
        format2 = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces0()
        self.assertTrue(
            format2.getIgnoreSurroundingSpaces(),
            "Expected getIgnoreSurroundingSpaces to return True when set to True",
        )

    def testWithIgnoreSurround_test2_decomposed(self) -> None:
        CSVFormat.DEFAULT = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces1(False)
        self.assertFalse(
            CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
            "Expected getIgnoreSurroundingSpaces to return False",
        )
        CSVFormat.DEFAULT = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces0()

    def testWithIgnoreSurround_test1_decomposed(self) -> None:
        csv_format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces1(False)
        self.assertFalse(csv_format.getIgnoreSurroundingSpaces())

    def testWithIgnoreSurround_test0_decomposed(self) -> None:
        CSVFormat.DEFAULT.withIgnoreSurroundingSpaces1(False)

    def testWithIgnoreEmptyLines_test3_decomposed(self) -> None:
        format1 = CSVFormat.DEFAULT.withIgnoreEmptyLines1(False)
        self.assertFalse(
            format1.getIgnoreEmptyLines(),
            "Expected getIgnoreEmptyLines() to return False when set to False",
        )

        format2 = CSVFormat.DEFAULT.withIgnoreEmptyLines0()
        self.assertTrue(
            format2.getIgnoreEmptyLines(),
            "Expected getIgnoreEmptyLines() to return True when set to True",
        )

    def testWithIgnoreEmptyLines_test2_decomposed(self) -> None:
        CSVFormat.DEFAULT = CSVFormat.DEFAULT.withIgnoreEmptyLines1(False)
        self.assertFalse(
            CSVFormat.DEFAULT.getIgnoreEmptyLines(),
            "Expected getIgnoreEmptyLines() to return False",
        )
        CSVFormat.DEFAULT = CSVFormat.DEFAULT.withIgnoreEmptyLines0()

    def testWithIgnoreEmptyLines_test1_decomposed(self) -> None:
        csv_format = CSVFormat.DEFAULT.withIgnoreEmptyLines1(False)
        self.assertFalse(csv_format.getIgnoreEmptyLines())

    def testWithIgnoreEmptyLines_test0_decomposed(self) -> None:
        CSVFormat.DEFAULT.withIgnoreEmptyLines1(False)

    def testWithHeaderComments_test95_decomposed(self) -> None:
        csv_format = CSVFormat.DEFAULT
        self.assertEqual('"', csv_format.getQuoteCharacter())
        self.assertFalse(csv_format.isCommentMarkerSet())
        self.assertFalse(csv_format.isEscapeCharacterSet())
        self.assertTrue(csv_format.isQuoteCharacterSet())
        self.assertFalse(csv_format.getSkipHeaderRecord())
        self.assertIsNone(csv_format.getQuoteMode())
        self.assertEqual(",", csv_format.getDelimiter())
        self.assertTrue(csv_format.getIgnoreEmptyLines())
        self.assertFalse(csv_format.getIgnoreHeaderCase())
        self.assertIsNone(csv_format.getCommentMarker())
        self.assertEqual("\r\n", csv_format.getRecordSeparator())
        self.assertFalse(csv_format.getTrailingDelimiter())
        self.assertFalse(csv_format.getAllowMissingColumnNames())
        self.assertFalse(csv_format.getTrim())
        self.assertFalse(csv_format.isNullStringSet())
        self.assertIsNone(csv_format.getNullString())
        self.assertFalse(csv_format.getIgnoreSurroundingSpaces())
        self.assertIsNone(csv_format.getEscapeCharacter())

        object_array = [None] * 8
        csv_format_two = csv_format.withHeaderComments(object_array)

        self.assertEqual('"', csv_format.getQuoteCharacter())
        self.assertFalse(csv_format.isCommentMarkerSet())
        self.assertFalse(csv_format.isEscapeCharacterSet())
        self.assertTrue(csv_format.isQuoteCharacterSet())
        self.assertFalse(csv_format.getSkipHeaderRecord())
        self.assertIsNone(csv_format.getQuoteMode())
        self.assertEqual(",", csv_format.getDelimiter())
        self.assertTrue(csv_format.getIgnoreEmptyLines())
        self.assertFalse(csv_format.getIgnoreHeaderCase())
        self.assertIsNone(csv_format.getCommentMarker())
        self.assertEqual("\r\n", csv_format.getRecordSeparator())
        self.assertFalse(csv_format.getTrailingDelimiter())
        self.assertFalse(csv_format.getAllowMissingColumnNames())
        self.assertFalse(csv_format.getTrim())
        self.assertFalse(csv_format.isNullStringSet())
        self.assertIsNone(csv_format.getNullString())
        self.assertFalse(csv_format.getIgnoreSurroundingSpaces())
        self.assertIsNone(csv_format.getEscapeCharacter())

        self.assertFalse(csv_format_two.getIgnoreHeaderCase())
        self.assertIsNone(csv_format_two.getQuoteMode())
        self.assertTrue(csv_format_two.getIgnoreEmptyLines())
        self.assertFalse(csv_format_two.getIgnoreSurroundingSpaces())
        self.assertIsNone(csv_format_two.getEscapeCharacter())
        self.assertFalse(csv_format_two.getTrim())
        self.assertFalse(csv_format_two.isEscapeCharacterSet())
        self.assertTrue(csv_format_two.isQuoteCharacterSet())
        self.assertFalse(csv_format_two.getSkipHeaderRecord())
        self.assertEqual('"', csv_format_two.getQuoteCharacter())
        self.assertFalse(csv_format_two.getAllowMissingColumnNames())
        self.assertIsNone(csv_format_two.getNullString())
        self.assertFalse(csv_format_two.isNullStringSet())
        self.assertFalse(csv_format_two.getTrailingDelimiter())
        self.assertEqual("\r\n", csv_format_two.getRecordSeparator())
        self.assertEqual(",", csv_format_two.getDelimiter())
        self.assertIsNone(csv_format_two.getCommentMarker())
        self.assertFalse(csv_format_two.isCommentMarkerSet())

        self.assertIsNot(csv_format, csv_format_two)
        self.assertIsNot(csv_format_two, csv_format)
        self.assertNotEqual(csv_format_two, csv_format)

        string = csv_format_two.format_(object_array)

        self.assertEqual('"', csv_format.getQuoteCharacter())
        self.assertFalse(csv_format.isCommentMarkerSet())
        self.assertFalse(csv_format.isEscapeCharacterSet())
        self.assertTrue(csv_format.isQuoteCharacterSet())
        self.assertFalse(csv_format.getSkipHeaderRecord())
        self.assertIsNone(csv_format.getQuoteMode())
        self.assertEqual(",", csv_format.getDelimiter())
        self.assertTrue(csv_format.getIgnoreEmptyLines())
        self.assertFalse(csv_format.getIgnoreHeaderCase())
        self.assertIsNone(csv_format.getCommentMarker())
        self.assertEqual("\r\n", csv_format.getRecordSeparator())
        self.assertFalse(csv_format.getTrailingDelimiter())
        self.assertFalse(csv_format.getAllowMissingColumnNames())
        self.assertFalse(csv_format.getTrim())
        self.assertFalse(csv_format.isNullStringSet())
        self.assertIsNone(csv_format.getNullString())
        self.assertFalse(csv_format.getIgnoreSurroundingSpaces())
        self.assertIsNone(csv_format.getEscapeCharacter())

        self.assertFalse(csv_format_two.getIgnoreHeaderCase())
        self.assertIsNone(csv_format_two.getQuoteMode())
        self.assertTrue(csv_format_two.getIgnoreEmptyLines())
        self.assertFalse(csv_format_two.getIgnoreSurroundingSpaces())
        self.assertIsNone(csv_format_two.getEscapeCharacter())
        self.assertFalse(csv_format_two.getTrim())
        self.assertFalse(csv_format_two.isEscapeCharacterSet())
        self.assertTrue(csv_format_two.isQuoteCharacterSet())
        self.assertFalse(csv_format_two.getSkipHeaderRecord())
        self.assertEqual('"', csv_format_two.getQuoteCharacter())
        self.assertFalse(csv_format_two.getAllowMissingColumnNames())
        self.assertIsNone(csv_format_two.getNullString())
        self.assertFalse(csv_format_two.isNullStringSet())
        self.assertFalse(csv_format_two.getTrailingDelimiter())
        self.assertEqual("\r\n", csv_format_two.getRecordSeparator())
        self.assertEqual(",", csv_format_two.getDelimiter())
        self.assertIsNone(csv_format_two.getCommentMarker())
        self.assertFalse(csv_format_two.isCommentMarkerSet())

        self.assertIsNot(csv_format, csv_format_two)
        self.assertIsNot(csv_format_two, csv_format)
        self.assertIsNotNone(string)
        self.assertNotEqual(csv_format, csv_format_two)
        self.assertNotEqual(csv_format_two, csv_format)
        self.assertEqual(",,,,,,,", string)

