    def testWithEmptyDuplicates_test4_decomposed(self) -> None:
        # Create a builder from the default CSVFormat
        builder = CSVFormat.DEFAULT.builder()

        # Set the duplicate header mode to ALLOW_EMPTY
        builder.setDuplicateHeaderMode(DuplicateHeaderMode.ALLOW_EMPTY)

        # Build the CSVFormat with the specified duplicate header mode
        format_with_empty_duplicates = builder.build()

        # Assert that the duplicate header mode is set to ALLOW_EMPTY
        self.assertEqual(
            DuplicateHeaderMode.ALLOW_EMPTY,
            format_with_empty_duplicates.getDuplicateHeaderMode(),
        )

        # Assert that duplicate header names are not allowed
        self.assertFalse(format_with_empty_duplicates.getAllowDuplicateHeaderNames())

