    def testTrim_test11_decomposed(self) -> None:
        format_with_trim = (
            CSVFormat.DEFAULT.withDelimiter(",")
            .withTrim0()
            .withQuote1(None)
            .withRecordSeparator1(Constants.CRLF)
        )

        # Test case 1
        in_value = "a,b,c"
        out = io.StringIO()
        format_with_trim.print2(in_value, out, True)
        self.assertEqual("a,b,c", out.getvalue())

        # Test case 2
        in_value = " x,y,z"
        out = io.StringIO()
        format_with_trim.print2(in_value, out, True)
        self.assertEqual("x,y,z", out.getvalue())

        # Test case 3
        in_value = ""
        out = io.StringIO()
        format_with_trim.print2(in_value, out, True)
        self.assertEqual("", out.getvalue())

        # Test case 4
        in_value = "header\r\n"
        out = io.StringIO()
        format_with_trim.print2(in_value, out, True)
        self.assertEqual("header", out.getvalue())

