    def testEscapeSameAsCommentStartThrowsExceptionForWrapperType_Deprecated_test2_decomposed(
        self,
    ) -> None:
        # Simulate Character.valueOf('!') in Python
        escape_char = "!"

        # Call withEscape1 with the escape character
        csv_format = CSVFormat.DEFAULT.withEscape1(escape_char)

        # Assert that an exception is raised when withCommentMarker1 is called with the same character
        with self.assertRaises(ValueError):
            csv_format.withCommentMarker1(escape_char)

