    def testEscapeSameAsCommentStartThrowsExceptionForWrapperType_test4_decomposed(
        self,
    ) -> None:
        # Simulate Character.valueOf('!') in Python
        escape_char = "!"
        comment_marker = "!"

        # Create a builder from the default CSVFormat
        builder = CSVFormat.DEFAULT.builder()

        # Set escape character
        builder.setEscape1(escape_char)

        # Set escape character and comment marker
        builder.setEscape1(escape_char).setCommentMarker1(comment_marker)

        # Assert that an exception is raised when building with conflicting settings
        with self.assertRaises(ValueError):
            builder.setEscape1(escape_char).setCommentMarker1(comment_marker).build()

