    def testEqualsWithNull_test10_decomposed(self) -> None:
        csv_format = CSVFormat.POSTGRESQL_TEXT
        self.assertEqual(
            "\\",
            csv_format.getEscapeCharacter(),
            "Escape character does not match expected value",
        )
        self.assertFalse(
            csv_format.getIgnoreSurroundingSpaces(),
            "Ignore surrounding spaces should be False",
        )
        self.assertFalse(
            csv_format.getTrailingDelimiter(), "Trailing delimiter should be False"
        )
        self.assertFalse(csv_format.getTrim(), "Trim should be False")
        self.assertFalse(
            csv_format.isQuoteCharacterSet(), "Quote character should not be set"
        )
        self.assertEqual(
            "\\N",
            csv_format.getNullString(),
            "Null string does not match expected value",
        )
