    def testEqualsOne_test75_decomposed(self) -> None:
        csv_format_one = CSVFormat.INFORMIX_UNLOAD
        csv_format_two = CSVFormat.MYSQL

        self.assertEqual("\\", csv_format_one.getEscapeCharacter())
        self.assertIsNone(csv_format_one.getQuoteMode())
        self.assertTrue(csv_format_one.getIgnoreEmptyLines())
        self.assertFalse(csv_format_one.getSkipHeaderRecord())
        self.assertFalse(csv_format_one.getIgnoreHeaderCase())
        self.assertIsNone(csv_format_one.getCommentMarker())
        self.assertFalse(csv_format_one.isCommentMarkerSet())
        self.assertTrue(csv_format_one.isQuoteCharacterSet())
        self.assertEqual("|", csv_format_one.getDelimiter())
        self.assertFalse(csv_format_one.getAllowMissingColumnNames())
        self.assertTrue(csv_format_one.isEscapeCharacterSet())
        self.assertEqual("\n", csv_format_one.getRecordSeparator())
        self.assertEqual('"', csv_format_one.getQuoteCharacter())
        self.assertFalse(csv_format_one.getTrailingDelimiter())
        self.assertFalse(csv_format_one.getTrim())
        self.assertFalse(csv_format_one.isNullStringSet())
        self.assertIsNone(csv_format_one.getNullString())
        self.assertFalse(csv_format_one.getIgnoreSurroundingSpaces())

        self.assertTrue(csv_format_two.isEscapeCharacterSet())
        self.assertIsNone(csv_format_two.getQuoteCharacter())
        self.assertFalse(csv_format_two.getAllowMissingColumnNames())
        self.assertEqual(QuoteMode.ALL_NON_NULL, csv_format_two.getQuoteMode())
        self.assertEqual("\t", csv_format_two.getDelimiter())
        self.assertEqual("\n", csv_format_two.getRecordSeparator())
        self.assertFalse(csv_format_two.isQuoteCharacterSet())
        self.assertTrue(csv_format_two.isNullStringSet())
        self.assertEqual("\\", csv_format_two.getEscapeCharacter())
        self.assertFalse(csv_format_two.getIgnoreHeaderCase())
        self.assertFalse(csv_format_two.getTrim())
        self.assertFalse(csv_format_two.getIgnoreEmptyLines())
        self.assertEqual("\\N", csv_format_two.getNullString())
        self.assertFalse(csv_format_two.getIgnoreSurroundingSpaces())
        self.assertFalse(csv_format_two.getTrailingDelimiter())
        self.assertFalse(csv_format_two.getSkipHeaderRecord())
        self.assertIsNone(csv_format_two.getCommentMarker())
        self.assertFalse(csv_format_two.isCommentMarkerSet())

        self.assertIsNot(csv_format_two, csv_format_one)
        self.assertNotEqual(csv_format_two, csv_format_one)

        self.assertEqual("\\", csv_format_one.getEscapeCharacter())
        self.assertIsNone(csv_format_one.getQuoteMode())
        self.assertTrue(csv_format_one.getIgnoreEmptyLines())
        self.assertFalse(csv_format_one.getSkipHeaderRecord())
        self.assertFalse(csv_format_one.getIgnoreHeaderCase())
        self.assertIsNone(csv_format_one.getCommentMarker())
        self.assertFalse(csv_format_one.isCommentMarkerSet())
        self.assertTrue(csv_format_one.isQuoteCharacterSet())
        self.assertEqual("|", csv_format_one.getDelimiter())
        self.assertFalse(csv_format_one.getAllowMissingColumnNames())
        self.assertTrue(csv_format_one.isEscapeCharacterSet())
        self.assertEqual("\n", csv_format_one.getRecordSeparator())
        self.assertEqual('"', csv_format_one.getQuoteCharacter())
        self.assertFalse(csv_format_one.getTrailingDelimiter())
        self.assertFalse(csv_format_one.getTrim())
        self.assertFalse(csv_format_one.isNullStringSet())
