    def testEqualsNullString_Deprecated_test10_decomposed(self) -> None:
        CSVFormat.newFormat("'")
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR)
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        )
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        ).withEscape0("+")
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        ).withEscape0("+").withIgnoreEmptyLines0()
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        ).withEscape0("+").withIgnoreEmptyLines0().withIgnoreSurroundingSpaces0()
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        ).withEscape0(
            "+"
        ).withIgnoreEmptyLines0().withIgnoreSurroundingSpaces0().withQuote0(
            '"'
        )
        CSVFormat.newFormat("'").withRecordSeparator0(Constants.CR).withCommentMarker0(
            "#"
        ).withEscape0(
            "+"
        ).withIgnoreEmptyLines0().withIgnoreSurroundingSpaces0().withQuote0(
            '"'
        ).withQuoteMode(
            QuoteMode.ALL
        )

        right = (
            CSVFormat.newFormat("'")
            .withRecordSeparator0(Constants.CR)
            .withCommentMarker0("#")
            .withEscape0("+")
            .withIgnoreEmptyLines0()
            .withIgnoreSurroundingSpaces0()
            .withQuote0('"')
            .withQuoteMode(QuoteMode.ALL)
            .withNullString("null")
        )

        left = right.withNullString("---")

        self.__assertNotEquals0(right, left)

